SELECT id, username, password, real_name, role, phone, email, student_id, department, avatar
FROM sys_user
WHERE username = #{username}
AND password = #{password}
AND status = 1
AND is_deleted = 0

SELECT id, username, real_name, role, phone, email, student_id, department FROM sys_user WHERE id IN
#{userId}
AND is_deleted = 0
